import React from 'react';
import { TrendingUp, TrendingDown, Target, Award } from 'lucide-react';

const QuickStats = ({ stats }) => {
  const budgetUsed = ((stats.totalSpent / stats.monthlyBudget) * 100).toFixed(1);
  const isOverBudget = stats.totalSpent > stats.monthlyBudget;

  return (
    <div className="stats-grid">
      <div className="stat-card">
        <div className="stat-value">${stats.totalSpent}</div>
        <div className="stat-label">Total Spent</div>
        <TrendingUp size={20} color="var(--primary-color)" style={{ marginTop: '0.5rem' }} />
      </div>
      
      <div className="stat-card">
        <div className="stat-value">{stats.expensesThisMonth}</div>
        <div className="stat-label">Transactions</div>
        <Target size={20} color="var(--accent-color)" style={{ marginTop: '0.5rem' }} />
      </div>
      
      <div className="stat-card">
        <div 
          className="stat-value"
          style={{ color: isOverBudget ? 'var(--danger-color)' : 'var(--primary-color)' }}
        >
          {budgetUsed}%
        </div>
        <div className="stat-label">Budget Used</div>
        {isOverBudget ? (
          <TrendingUp size={20} color="var(--danger-color)" style={{ marginTop: '0.5rem' }} />
        ) : (
          <TrendingDown size={20} color="var(--primary-color)" style={{ marginTop: '0.5rem' }} />
        )}
      </div>
      
      <div className="stat-card">
        <div className="stat-value">{stats.topCategory}</div>
        <div className="stat-label">Top Category</div>
        <Award size={20} color="var(--warning-color)" style={{ marginTop: '0.5rem' }} />
      </div>
    </div>
  );
};

export default QuickStats;
